import React, { useState, useEffect, useRef } from 'react';
import { useParams, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useSocket } from '../context/SocketContext';
import axios from 'axios';
import './GameRoom.css';

function GameRoom() {
  const { roomId } = useParams();
  const location = useLocation();
  const navigate = useNavigate();
  const { user, updateBalance } = useAuth();
  const { socket, isConnected, on, emit } = useSocket();
  
  const [game, setGame] = useState(null);
  const [cartelas, setCartelas] = useState(location.state?.cartelas || []);
  const [calledNumbers, setCalledNumbers] = useState([]);
  const [countdown, setCountdown] = useState(null);
  const [gameActive, setGameActive] = useState(false);
  const [winner, setWinner] = useState(null);
  const [lastCalled, setLastCalled] = useState(null);
  const [players, setPlayers] = useState([]);
  const [pool, setPool] = useState(0);
  const [loading, setLoading] = useState(true);
  
  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

  const parseCartelaData = (cartelaData) => {
    if (!cartelaData) return null;
    if (typeof cartelaData === 'string') {
      try {
        return JSON.parse(cartelaData);
      } catch (e) {
        return null;
      }
    }
    return cartelaData;
  };

  const getLetter = (number) => {
    if (number <= 15) return 'B';
    if (number <= 30) return 'I';
    if (number <= 45) return 'N';
    if (number <= 60) return 'G';
    return 'O';
  };

  const isNumberMarked = (cartela, number) => {
    const markedNumbers = cartela.marked_numbers || [];
    return markedNumbers.includes(number);
  };

  const toggleMode = (cartelaId, currentMode) => {
    if (emit) {
      emit('toggle_mode', { cartelaId, isAutoMode: !currentMode });
      setCartelas(prev => prev.map(c => 
        c.id === cartelaId ? { ...c, is_auto_mode: !currentMode } : c
      ));
    }
  };

  const markNumber = (cartelaId, number) => {
    if (!gameActive) return;
    if (emit) emit('mark_number', { gameId: game?.id, cartelaId, number });
  };

  const callBingo = (cartelaId) => {
    if (!gameActive) return;
    if (window.confirm('Are you sure you want to call BINGO?')) {
      if (emit) emit('call_bingo', { gameId: game?.id, cartelaId });
    }
  };

  const leaveRoom = async () => {
    if (gameActive) {
      alert('Cannot leave during active game!');
      return;
    }
    if (window.confirm('Are you sure you want to leave this room?')) {
      try {
        const token = localStorage.getItem('token');
        await axios.post(`${API_URL}/game/rooms/${roomId}/leave`, {}, {
          headers: { Authorization: `Bearer ${token}` }
        });
        navigate('/');
      } catch (error) {
        alert('Failed to leave room');
      }
    }
  };

  const calculatePotentialWinning = () => {
    if (!pool || pool <= 0) return '0.00';
    const WINNER_PERCENTAGE = 78.75;
    return ((pool * WINNER_PERCENTAGE) / 100).toFixed(2);
  };

  const fetchGameState = async () => {
    if (!location.state?.gameId) return;
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`${API_URL}/game/games/${location.state.gameId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setGame(response.data.game);
      setCartelas(response.data.cartelas || []);
      setPlayers(response.data.players || []);
      setPool(response.data.game.total_pool || 0);
      if (response.data.game.status === 'active') setGameActive(true);
    } catch (error) {
      navigate('/');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (location.state?.gameId) fetchGameState();
    else navigate('/');
  }, [location.state]);

  useEffect(() => {
    if (!socket) return;
    if (game?.id) emit('join_game', { gameId: game.id });

    const unsubscribeCountdown = on('countdown', (data) => setCountdown(data.seconds));
    const unsubscribeWaiting = on('waiting_for_players', () => { setGameActive(false); setCountdown(null); });
    const unsubscribeGameState = on('game_state', (data) => { setCalledNumbers(data.calledNumbers || []); setGameActive(true); setCountdown(null); });
    const unsubscribeNumberCalled = on('number_called', (data) => {
      setLastCalled({ number: data.number, letter: data.letter });
      setCalledNumbers(data.calledNumbers || []);
      setGameActive(true);
      setCountdown(null);
    });
    const unsubscribeAutoMarked = on('auto_marked', (data) => {
      setCartelas(prev => prev.map(c => 
        c.id === data.cartelaId ? { ...c, marked_numbers: [...(c.marked_numbers || []), data.number] } : c
      ));
    });
    const unsubscribeNumberMarked = on('number_marked', (data) => {
      setCartelas(prev => prev.map(c => 
        c.id === data.cartelaId ? { ...c, marked_numbers: [...(c.marked_numbers || []), data.number] } : c
      ));
    });
    const unsubscribeGameEnded = on('game_ended', (data) => {
      setGameActive(false);
      setWinner(data.winners);
      setTimeout(() => navigate('/'), 5000);
    });
    const unsubscribeInvalidBingo = on('invalid_bingo', () => alert('Invalid BINGO pattern!'));
    const unsubscribeBonusAwarded = on('bonus_awarded', (data) => {
      alert(`🎁 ${data.message}`);
      if (updateBalance && user) updateBalance((user.wallet_balance || 0) + (data.amount || 0));
    });

    return () => {
      unsubscribeCountdown(); unsubscribeWaiting(); unsubscribeGameState(); unsubscribeNumberCalled();
      unsubscribeAutoMarked(); unsubscribeNumberMarked(); unsubscribeGameEnded(); unsubscribeInvalidBingo(); unsubscribeBonusAwarded();
    };
  }, [socket, game]);

  if (loading) return (
    <div className="game-loading">
      <div className="loader"></div>
      <p>Loading game...</p>
    </div>
  );

  // Bingo Board Component with casino styling
  const BingoBoard = () => {
    const bingoNumbers = {
      B: Array.from({ length: 15 }, (_, i) => i + 1),
      I: Array.from({ length: 15 }, (_, i) => i + 16),
      N: Array.from({ length: 15 }, (_, i) => i + 31),
      G: Array.from({ length: 15 }, (_, i) => i + 46),
      O: Array.from({ length: 15 }, (_, i) => i + 61)
    };
    const isNumberCalled = (num) => calledNumbers.includes(num);
    
    return (
      <div className="casino-card" style={{ padding: '12px', marginBottom: '12px' }}>
        <h3 style={{ textAlign: 'center', color: '#ffd700', marginBottom: '10px', fontSize: '0.9rem' }}>🎯 BINGO BOARD</h3>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ background: 'rgba(255, 215, 0, 0.2)', color: '#ffd700', padding: '6px', fontSize: '0.8rem' }}>B</th>
              <th style={{ background: 'rgba(255, 215, 0, 0.2)', color: '#ffd700', padding: '6px', fontSize: '0.8rem' }}>I</th>
              <th style={{ background: 'rgba(255, 215, 0, 0.2)', color: '#ffd700', padding: '6px', fontSize: '0.8rem' }}>N</th>
              <th style={{ background: 'rgba(255, 215, 0, 0.2)', color: '#ffd700', padding: '6px', fontSize: '0.8rem' }}>G</th>
              <th style={{ background: 'rgba(255, 215, 0, 0.2)', color: '#ffd700', padding: '6px', fontSize: '0.8rem' }}>O</th>
            </tr>
          </thead>
          <tbody>
            {[...Array(15)].map((_, row) => (
              <tr key={row}>
                <td style={{ padding: '4px', textAlign: 'center', border: '1px solid rgba(255,255,255,0.1)', fontSize: '0.7rem', background: isNumberCalled(bingoNumbers.B[row]) ? 'linear-gradient(135deg, #ffd700, #b8860b)' : 'rgba(255,255,255,0.05)', color: isNumberCalled(bingoNumbers.B[row]) ? '#1a1a2e' : '#fff' }}>{bingoNumbers.B[row]}</td>
                <td style={{ padding: '4px', textAlign: 'center', border: '1px solid rgba(255,255,255,0.1)', fontSize: '0.7rem', background: isNumberCalled(bingoNumbers.I[row]) ? 'linear-gradient(135deg, #ffd700, #b8860b)' : 'rgba(255,255,255,0.05)', color: isNumberCalled(bingoNumbers.I[row]) ? '#1a1a2e' : '#fff' }}>{bingoNumbers.I[row]}</td>
                <td style={{ padding: '4px', textAlign: 'center', border: '1px solid rgba(255,255,255,0.1)', fontSize: '0.7rem', background: isNumberCalled(bingoNumbers.N[row]) ? 'linear-gradient(135deg, #ffd700, #b8860b)' : 'rgba(255,255,255,0.05)', color: isNumberCalled(bingoNumbers.N[row]) ? '#1a1a2e' : '#fff' }}>{bingoNumbers.N[row]}</td>
                <td style={{ padding: '4px', textAlign: 'center', border: '1px solid rgba(255,255,255,0.1)', fontSize: '0.7rem', background: isNumberCalled(bingoNumbers.G[row]) ? 'linear-gradient(135deg, #ffd700, #b8860b)' : 'rgba(255,255,255,0.05)', color: isNumberCalled(bingoNumbers.G[row]) ? '#1a1a2e' : '#fff' }}>{bingoNumbers.G[row]}</td>
                <td style={{ padding: '4px', textAlign: 'center', border: '1px solid rgba(255,255,255,0.1)', fontSize: '0.7rem', background: isNumberCalled(bingoNumbers.O[row]) ? 'linear-gradient(135deg, #ffd700, #b8860b)' : 'rgba(255,255,255,0.05)', color: isNumberCalled(bingoNumbers.O[row]) ? '#1a1a2e' : '#fff' }}>{bingoNumbers.O[row]}</td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{ marginTop: '10px', display: 'flex', justifyContent: 'space-between', padding: '5px 10px', background: 'rgba(0,0,0,0.3)', borderRadius: '8px', fontSize: '0.7rem' }}>
          <span>📊 Called: {calledNumbers.length}/75</span>
          <span style={{ color: '#ffd700' }}>{Math.round((calledNumbers.length / 75) * 100)}%</span>
        </div>
      </div>
    );
  };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #0a0a0f 0%, #1a1a2e 100%)', padding: '12px' }}>
      {/* Header */}
      <div style={{ background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(10px)', borderRadius: '12px', padding: '10px 15px', marginBottom: '12px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '10px', borderBottom: '2px solid #ffd700' }}>
        <div>
          <div style={{ fontSize: '1.2rem', fontWeight: 'bold', background: 'linear-gradient(135deg, #ffd700, #ffb347)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>🎰 {game?.room_name || roomId}</div>
          <div style={{ display: 'flex', gap: '10px', marginTop: '5px' }}>
            <span style={{ background: 'rgba(255,215,0,0.15)', border: '1px solid rgba(255,215,0,0.3)', padding: '3px 8px', borderRadius: '20px', fontSize: '0.7rem', color: '#ffd700' }}>💰 Pool: {pool} Birr</span>
            <span style={{ background: 'rgba(255,215,0,0.15)', border: '1px solid rgba(255,215,0,0.3)', padding: '3px 8px', borderRadius: '20px', fontSize: '0.7rem', color: '#ffd700' }}>👥 {players.length}</span>
            <span style={{ background: 'rgba(255,215,0,0.15)', border: '1px solid rgba(255,215,0,0.3)', padding: '3px 8px', borderRadius: '20px', fontSize: '0.7rem', color: '#ffd700' }}>💵 {user?.wallet_balance || 0} Birr</span>
          </div>
        </div>
        {!gameActive && <button onClick={leaveRoom} style={{ background: 'rgba(220,38,38,0.2)', border: '1px solid #dc2626', padding: '5px 15px', borderRadius: '20px', color: '#ff6b6b', cursor: 'pointer' }}>Exit Room</button>}
      </div>

      {/* Status Bar */}
      <div style={{ background: 'rgba(0,0,0,0.5)', borderRadius: '12px', padding: '10px 15px', marginBottom: '12px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: '10px' }}>
        {gameActive ? (
          <>
            <span style={{ background: 'rgba(220,38,38,0.3)', padding: '4px 12px', borderRadius: '20px', fontSize: '0.75rem', animation: 'pulse 1s infinite' }}>🔴 GAME ACTIVE</span>
            <div><span style={{ fontSize: '0.7rem', color: '#888' }}>Last:</span> <span style={{ fontSize: '1.2rem', fontWeight: 'bold', color: '#ffd700' }}>{lastCalled?.letter}{lastCalled?.number}</span></div>
            <div style={{ background: 'rgba(255,215,0,0.15)', padding: '4px 12px', borderRadius: '20px', fontSize: '0.75rem', color: '#ffd700' }}>🏆 Win: {calculatePotentialWinning()} Birr</div>
          </>
        ) : countdown !== null && countdown > 0 ? (
          <>
            <span style={{ background: 'rgba(255,215,0,0.2)', padding: '4px 12px', borderRadius: '20px', fontSize: '0.75rem', color: '#ffd700' }}>⏰ Starts in: {countdown}s</span>
            <div style={{ background: 'rgba(255,215,0,0.15)', padding: '4px 12px', borderRadius: '20px', fontSize: '0.75rem', color: '#ffd700' }}>🏆 Win: {calculatePotentialWinning()} Birr</div>
          </>
        ) : (
          <>
            <span style={{ background: 'rgba(255,215,0,0.2)', padding: '4px 12px', borderRadius: '20px', fontSize: '0.75rem', color: '#ffd700' }}>⏳ Waiting for players... (2+)</span>
            <div style={{ background: 'rgba(255,215,0,0.15)', padding: '4px 12px', borderRadius: '20px', fontSize: '0.75rem', color: '#ffd700' }}>🏆 Win: {calculatePotentialWinning()} Birr</div>
          </>
        )}
      </div>

      {/* Two Column Layout */}
      <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
        {/* Left Column - Cartelas */}
        <div style={{ flex: '1', minWidth: '250px' }}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: 'calc(100vh - 160px)', overflowY: 'auto', paddingRight: '5px' }}>
            {cartelas.map((cartela, idx) => {
              const cartelaData = parseCartelaData(cartela.cartela_data);
              if (!cartelaData) return null;
              const isAuto = cartela.is_auto_mode;
              
              return (
                <div key={cartela.id} style={{ background: 'rgba(0,0,0,0.5)', backdropFilter: 'blur(10px)', borderRadius: '12px', padding: '10px', border: '1px solid rgba(255,215,0,0.2)' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px', flexWrap: 'wrap', gap: '6px' }}>
                    <span style={{ background: 'linear-gradient(135deg, #ffd700, #b8860b)', padding: '2px 8px', borderRadius: '15px', fontSize: '0.65rem', fontWeight: 'bold', color: '#1a1a2e' }}>#{idx + 1} 🍀{cartela.lucky_number}</span>
                    <div style={{ display: 'flex', gap: '6px' }}>
                      <button onClick={() => toggleMode(cartela.id, isAuto)} style={{ padding: '3px 10px', borderRadius: '15px', fontSize: '0.6rem', border: 'none', cursor: 'pointer', background: isAuto ? 'linear-gradient(135deg, #10b981, #059669)' : 'linear-gradient(135deg, #3b82f6, #2563eb)', color: 'white' }}>{isAuto ? '🤖 Auto' : '✋ Manual'}</button>
                      <button onClick={() => callBingo(cartela.id)} disabled={!gameActive} style={{ background: 'linear-gradient(135deg, #dc2626, #991b1b)', border: 'none', padding: '3px 12px', borderRadius: '15px', color: 'white', fontWeight: 'bold', fontSize: '0.65rem', cursor: 'pointer', opacity: !gameActive ? 0.5 : 1 }}>BINGO!</button>
                    </div>
                  </div>
                  <div style={{ width: '100%' }}>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', textAlign: 'center', fontWeight: 'bold', color: '#ffd700', marginBottom: '4px', fontSize: '0.6rem' }}>
                      <span>B</span><span>I</span><span>N</span><span>G</span><span>O</span>
                    </div>
                    {[0, 1, 2, 3, 4].map(row => (
                      <div key={row} style={{ display: 'grid', gridTemplateColumns: 'repeat(5, 1fr)', gap: '3px', marginBottom: '3px' }}>
                        {[0, 1, 2, 3, 4].map(col => {
                          const number = cartelaData[col]?.[row];
                          const isFree = number === 'FREE';
                          const isMarked = isFree || isNumberMarked(cartela, number);
                          return (
                            <div key={`${col}-${row}`} 
                              onClick={() => { if (gameActive && !isAuto && number !== 'FREE' && !isMarked) markNumber(cartela.id, number); }}
                              style={{ aspectRatio: '1', background: isMarked ? (isFree ? 'linear-gradient(135deg, #10b981, #059669)' : 'linear-gradient(135deg, #ffd700, #b8860b)') : 'rgba(255,255,255,0.08)', borderRadius: '5px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold', fontSize: '0.6rem', cursor: isAuto ? 'default' : 'pointer', border: '1px solid rgba(255,255,255,0.1)', color: isMarked ? '#1a1a2e' : '#fff' }}>
                              {isFree ? '⭐' : number}
                            </div>
                          );
                        })}
                      </div>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Right Column - BINGO Board & Recent Numbers */}
        <div style={{ flex: '1', minWidth: '280px' }}>
          <BingoBoard />
          <div style={{ background: 'rgba(0,0,0,0.4)', borderRadius: '12px', padding: '10px' }}>
            <div style={{ fontSize: '0.75rem', color: '#ffd700', marginBottom: '8px' }}>📢 Recent Calls</div>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
              {calledNumbers.slice(-12).reverse().map((num, idx) => (
                <span key={idx} style={{ background: 'rgba(255,215,0,0.2)', border: '1px solid rgba(255,215,0,0.3)', padding: '3px 8px', borderRadius: '15px', fontSize: '0.65rem', fontWeight: 'bold', color: '#ffd700' }}>{getLetter(num)}{num}</span>
              ))}
              {calledNumbers.length === 0 && <span style={{ background: 'rgba(255,215,0,0.2)', border: '1px solid rgba(255,215,0,0.3)', padding: '3px 8px', borderRadius: '15px', fontSize: '0.65rem', color: '#ffd700' }}>Waiting...</span>}
            </div>
          </div>
        </div>
      </div>

      {/* Winner Modal */}
      {winner && winner.length > 0 && (
        <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.9)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 }}>
          <div style={{ background: 'linear-gradient(135deg, #1a1a2e, #0a0a0f)', border: '2px solid #ffd700', borderRadius: '20px', padding: '30px', textAlign: 'center', animation: 'slideUp 0.3s' }}>
            <div style={{ fontSize: '50px', marginBottom: '15px' }}>🏆</div>
            <h2 style={{ color: '#ffd700', fontSize: '28px', marginBottom: '15px' }}>WINNER!</h2>
            {winner.map((w, idx) => <p key={idx} style={{ color: '#fff' }}>{w.userId === user?.id ? '🎉 YOU WON! 🎉' : `Player ${w.userId} won!`}</p>)}
          </div>
        </div>
      )}

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.6; }
        }
        @keyframes slideUp {
          from { transform: translateY(50px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
        .cartelas-container::-webkit-scrollbar {
          width: 3px;
        }
        .cartelas-container::-webkit-scrollbar-track {
          background: rgba(255, 255, 255, 0.1);
        }
        .cartelas-container::-webkit-scrollbar-thumb {
          background: #ffd700;
        }
      `}</style>
    </div>
  );
}

export default GameRoom;
